#include "max31855.h"
#include <SPI.h>
#include <Adafruit_MAX31855.h>
static Adafruit_MAX31855 tc(5);
static float _t=0,_i=0;
static unsigned long _last=0;
void max31855_setup(){if(!tc.begin()){Serial.println("[max31855] Fail!");return;}Serial.println("[max31855] OK");}
void max31855_loop(){if(millis()-_last<1000)return;_last=millis();_t=tc.readCelsius();_i=tc.readInternal();}
float max31855_get_temperature(){return _t;}
float max31855_get_internal(){return _i;}
